288	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
289	        return -1;
290	    }
291	
292	    // Check for quad output: [] <- expr (IBM 5100 convention)
293	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
294	        parse_pos = 2;
295	        int expr = parse_node(0);
296	        if (parse_err) return -1;
