300	        node_right[n] = expr;
301	        return n;
302	    }
303	
304	    // Check for shared variable indexed write: IDENT[expr] <- expr
305	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
306	        int sym_idx = sym_lookup(line, tok_val[0]);
307	        if (sym_idx < 0) { return -1; }
308	        parse_pos = 2;
309	        int idx_expr = parse_node(0);
310	        if (parse_err) return -1;
311	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
312	        parse_pos++;
