1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
12	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
13	int qled_shadow;
14	
15	// Apply a binary op to two scalars
16	int eval_binop_scalar(int op, int a, int b) {
17	    if (op == TOK_PLUS)       return a + b;
18	    if (op == TOK_MINUS)      return a - b;
19	    if (op == TOK_STAR)       return a * b;
20	    if (op == TOK_SLASH) {
21	        if (b == 0) { eval_err = 1; return 0; }
22	        return a / b;
23	    }
24	    eval_err = 1;
25	    return 0;
26	}
27	
28	// Evaluate AST node, return heap index of result array.
29	// On error, sets eval_err and returns -1.
30	int eval(int n) {
31	    if (eval_err) return -1;
32	    if (n < 0 || n >= node_count) {
33	        eval_err = 1;
34	        return -1;
35	    }
36	
37	    int ty = node_type[n];
38	
39	    if (ty == NODE_NUM) {
40	        int r = arr_scalar(node_val[n]);
41	        if (r < 0) { eval_err = 5; return -1; }
42	        return r;
43	    }
44	
45	    if (ty == NODE_VEC) {
46	        return node_val[n];
47	    }
48	
49	    if (ty == NODE_IDENT) {
50	        int idx = node_val[n];
51	        if (!sym_set_flag[idx]) {
52	            eval_err = 2;
53	            return -1;
54	        }
55	        return sym_val[idx];
56	    }
57	
58	    if (ty == NODE_ASSIGN) {
59	        int idx = node_val[n];
60	        int v = eval(node_right[n]);
61	        if (eval_err) return -1;
62	        sym_val[idx] = v;
63	        sym_set_flag[idx] = 1;
64	        return v;
65	    }
66	
67	    if (ty == NODE_QOUT) {
68	        int v = eval(node_right[n]);
69	        if (eval_err) return -1;
70	        return v;
71	    }
72	
73	    if (ty == NODE_QLED) {
74	        // Read LED D2 from shadow register (1=on, 0=off)
75	        int r = arr_scalar(qled_shadow);
76	        if (r < 0) { eval_err = 5; return -1; }
77	        return r;
78	    }
79	
80	    if (ty == NODE_QSW) {
81	        // Read switch S2: bit 0 of 0xFF0000, inverted (1=pressed, 0=released)
82	        int raw = *(char *)0xFF0000;
83	        int val = (raw ^ 1) & 1;
84	        int r = arr_scalar(val);
85	        if (r < 0) { eval_err = 5; return -1; }
86	        return r;
87	    }
88	
89	    if (ty == NODE_QLED_ASSIGN) {
90	        int v = eval(node_right[n]);
91	        if (eval_err) return -1;
92	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
93	        int val = arr_get(v, 0) & 1;
94	        qled_shadow = val;
95	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
96	        *(char *)0xFF0000 = val ^ 1;
97	        return v;
98	    }
99	
100	    if (ty == NODE_QSVO) {
101	        // Shared variable offer: IDENT qsvo AP
102	        // Evaluate AP number, couple symbol if AP supported
103	        int v = eval(node_right[n]);
104	        if (eval_err) return -1;
105	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
106	        int ap = arr_get(v, 0);
107	        int sym_idx = node_val[n];
108	        if (ap == 242) {
109	            // AP 242: MMIO byte access (FF0000+offset)
110	            svo_ap[sym_idx] = 242;
111	            int r = arr_scalar(2);
112	            if (r < 0) { eval_err = 5; return -1; }
113	            return r;
114	        }
115	        // Unknown AP: return 0 (not coupled)
116	        svo_ap[sym_idx] = 0;
117	        int r = arr_scalar(0);
118	        if (r < 0) { eval_err = 5; return -1; }
119	        return r;
120	    }
121	
122	    if (ty == NODE_SVO_READ) {
123	        // Shared variable indexed read: IDENT[N]
124	        int sym_idx = node_val[n];
125	        int ap = svo_ap[sym_idx];
126	        if (ap == 0) { eval_err = 2; return -1; }  // VALUE ERROR: not coupled
127	        int v = eval(node_right[n]);
128	        if (eval_err) return -1;
129	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
130	        int offset = arr_get(v, 0);
131	        if (ap == 242) {
132	            // AP 242: MMIO byte access at FF0000+offset
133	            int addr = 0xFF0000 + offset;
134	            int val = *(char *)addr;
135	            val = val & 0xFF;
136	            int r = arr_scalar(val);
137	            if (r < 0) { eval_err = 5; return -1; }
138	            return r;
139	        }
140	        eval_err = 1;
141	        return -1;
142	    }
143	
144	    if (ty == NODE_SVO_WRITE) {
145	        // Shared variable indexed write: IDENT[N] <- expr
146	        int sym_idx = node_val[n];
147	        int ap = svo_ap[sym_idx];
148	        if (ap == 0) { eval_err = 2; return -1; }  // VALUE ERROR: not coupled
149	        int idx = eval(node_left[n]);
150	        if (eval_err) return -1;
151	        if (arr_rank(idx) != 0) { eval_err = 4; return -1; }
152	        int offset = arr_get(idx, 0);
153	        int v = eval(node_right[n]);
154	        if (eval_err) return -1;
155	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
156	        int val = arr_get(v, 0);
157	        if (ap == 242) {
158	            // AP 242: MMIO byte write at FF0000+offset
159	            int addr = 0xFF0000 + offset;
160	            *(char *)addr = val & 0xFF;
161	            return v;
162	        }
163	        eval_err = 1;
164	        return -1;
165	    }
166	
167	    if (ty == NODE_NEG) {
168	        int v = eval(node_right[n]);
169	        if (eval_err) return -1;
170	        int rk = arr_rank(v);
171	        if (rk == 0) {
172	            int r = arr_scalar(0 - arr_get(v, 0));
173	            if (r < 0) { eval_err = 5; return -1; }
174	            return r;
175	        }
176	        // Negate each element of vector
177	        if (rk == 1) {
178	            int sz = arr_size(v);
179	            int r = arr_vector(sz);
180	            if (r < 0) { eval_err = 5; return -1; }
181	            int i = 0;
182	            while (i < sz) {
183	                arr_set(r, i, 0 - arr_get(v, i));
184	                i++;
185	            }
186	            return r;
187	        }
188	        // Negate each element of matrix
189	        if (rk == 2) {
190	            int d0 = arr_dim0(v);
191	            int d1 = arr_dim1(v);
192	            int sz = d0 * d1;
193	            int r = arr_new(2, d0, d1);
194	            if (r < 0) { eval_err = 5; return -1; }
195	            int i = 0;
196	            while (i < sz) {
197	                arr_set(r, i, 0 - arr_get(v, i));
198	                i++;
199	            }
200	            return r;
201	        }
202	        eval_err = 4;
203	        return -1;
204	    }
205	
206	    if (ty == NODE_MONAD) {
207	        int v = eval(node_right[n]);
208	        if (eval_err) return -1;
209	        int res_id = node_val[n];
210	
211	        if (res_id == RES_IOTA) {
212	            // iota N: generate vector 0 1 2 ... N-1
213	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
214	            int count = arr_get(v, 0);
215	            if (count < 0) { eval_err = 1; return -1; }
216	            int r = arr_vector(count);
217	            if (r < 0) { eval_err = 5; return -1; }
218	            int i = 0;
219	            while (i < count) {
220	                arr_set(r, i, i);
221	                i++;
222	            }
223	            return r;
224	        }
225	
226	        if (res_id == RES_RHO) {
227	            // rho A: return shape of A
228	            int rk = arr_rank(v);
229	            if (rk == 0) {
230	                // Scalar: shape is empty vector
231	                int r = arr_vector(0);
232	                if (r < 0) { eval_err = 5; return -1; }
233	                return r;
234	            }
235	            if (rk == 1) {
236	                // Vector: shape is 1-element vector with length
237	                int r = arr_scalar(arr_dim0(v));
238	                if (r < 0) { eval_err = 5; return -1; }
239	                return r;
240	            }
241	            if (rk == 2) {
242	                // Matrix: shape is 2-element vector (rows cols)
243	                int r = arr_vector(2);
244	                if (r < 0) { eval_err = 5; return -1; }
245	                arr_set(r, 0, arr_dim0(v));
246	                arr_set(r, 1, arr_dim1(v));
247	                return r;
248	            }
249	            eval_err = 4;
250	            return -1;
251	        }
252	
253	        if (res_id == RES_REV) {
254	            // rev A: reverse a vector
255	            int rk = arr_rank(v);
256	            if (rk == 0) {
257	                // Scalar: reverse is identity
258	                return v;
259	            }
260	            if (rk == 1) {
261	                int sz = arr_size(v);
262	                int r = arr_vector(sz);
263	                if (r < 0) { eval_err = 5; return -1; }
264	                int i = 0;
265	                while (i < sz) {
266	                    arr_set(r, i, arr_get(v, sz - 1 - i));
267	                    i++;
268	                }
269	                return r;
270	            }
271	            eval_err = 4;
272	            return -1;
273	        }
274	
275	        if (res_id == RES_CAT) {
276	            // Monadic cat: ravel (flatten to 1D vector)
277	            int rk = arr_rank(v);
278	            if (rk == 0) {
279	                // Scalar -> 1-element vector
280	                int r = arr_vector(1);
281	                if (r < 0) { eval_err = 5; return -1; }
282	                arr_set(r, 0, arr_get(v, 0));
283	                return r;
284	            }
285	            if (rk == 1) {
286	                // Vector: already 1D, return as-is
287	                return v;
288	            }
289	            if (rk == 2) {
290	                // Matrix -> vector of all elements
291	                int sz = arr_size(v);
292	                int r = arr_vector(sz);
293	                if (r < 0) { eval_err = 5; return -1; }
294	                int i = 0;
295	                while (i < sz) {
296	                    arr_set(r, i, arr_get(v, i));
297	                    i++;
298	                }
299	                return r;
300	            }
301	            eval_err = 4;
302	            return -1;
303	        }
304	
305	        // Unknown monadic function
306	        eval_err = 1;
307	        return -1;
308	    }
309	
310	    if (ty == NODE_REDUCE) {
311	        int v = eval(node_right[n]);
312	        if (eval_err) return -1;
313	        int op = node_val[n];
314	        int rk = arr_rank(v);
315	
316	        // Scalar reduce: just return the scalar
317	        if (rk == 0) {
318	            return v;
319	        }
320	
321	        // Vector reduce: right-to-left fold
322	        if (rk == 1) {
323	            int sz = arr_size(v);
324	            if (sz == 0) {
325	                // Empty vector: return identity element
326	                int id;
327	                if (op == TOK_PLUS || op == TOK_MINUS) id = 0;
328	                else if (op == TOK_STAR || op == TOK_SLASH) id = 1;
329	                else { eval_err = 1; return -1; }
330	                int r = arr_scalar(id);
331	                if (r < 0) { eval_err = 5; return -1; }
332	                return r;
333	            }
334	            int acc = arr_get(v, sz - 1);
335	            int i = sz - 2;
336	            while (i >= 0) {
337	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
338	                if (eval_err) return -1;
339	                i--;
340	            }
341	            int r = arr_scalar(acc);
342	            if (r < 0) { eval_err = 5; return -1; }
343	            return r;
344	        }
345	
346	        // Unsupported rank for reduce
347	        eval_err = 4;
348	        return -1;
349	    }
350	
351	    if (ty == NODE_DYAD) {
352	        int lv = eval(node_left[n]);
353	        if (eval_err) return -1;
354	        int rv = eval(node_right[n]);
355	        if (eval_err) return -1;
356	        int res_id = node_val[n];
357	
358	        if (res_id == RES_RHO) {
359	            // S rho A: reshape A to shape S with cyclic fill
360	            // S is scalar -> result is vector of that length
361	            // S is 2-element vector -> result is matrix
362	            int lrk = arr_rank(lv);
363	            int new_rank;
364	            int d0;
365	            int d1;
366	
367	            if (lrk == 0) {
368	                // Scalar shape -> vector
369	                new_rank = 1;
370	                d0 = arr_get(lv, 0);
371	                d1 = 0;
372	                if (d0 < 0) { eval_err = 1; return -1; }
373	            } else if (lrk == 1) {
374	                int lsz = arr_size(lv);
375	                if (lsz == 1) {
376	                    new_rank = 1;
377	                    d0 = arr_get(lv, 0);
378	                    d1 = 0;
379	                    if (d0 < 0) { eval_err = 1; return -1; }
380	                } else if (lsz == 2) {
381	                    new_rank = 2;
382	                    d0 = arr_get(lv, 0);
383	                    d1 = arr_get(lv, 1);
384	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
385	                } else {
386	                    // Only rank 1 and 2 supported
387	                    eval_err = 4;
388	                    return -1;
389	                }
390	            } else {
391	                eval_err = 4;
392	                return -1;
393	            }
394	
395	            int r = arr_new(new_rank, d0, d1);
396	            if (r < 0) { eval_err = 5; return -1; }
397	
398	            int total = arr_size(r);
399	            int src_sz = arr_size(rv);
400	            if (src_sz == 0) { eval_err = 3; return -1; }
401	
402	            int i = 0;
403	            while (i < total) {
404	                arr_set(r, i, arr_get(rv, i % src_sz));
405	                i++;
406	            }
407	            return r;
408	        }
409	
410	        if (res_id == RES_TAKE) {
411	            // N take A: take first N elements/rows (negative N = from end)
412	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
413	            int count = arr_get(lv, 0);
414	            int rrk = arr_rank(rv);
415	
416	            if (rrk <= 1) {
417	                int sz = arr_size(rv);
418	                int abs_n = count;
419	                if (abs_n < 0) abs_n = 0 - abs_n;
420	                if (abs_n > sz) { eval_err = 3; return -1; }
421	
422	                int r = arr_vector(abs_n);
423	                if (r < 0) { eval_err = 5; return -1; }
424	                int start = 0;
425	                if (count < 0) start = sz - abs_n;
426	                int i = 0;
427	                while (i < abs_n) {
428	                    arr_set(r, i, arr_get(rv, start + i));
429	                    i++;
430	                }
431	                return r;
432	            }
433	
434	            if (rrk == 2) {
435	                int rows = arr_dim0(rv);
436	                int cols = arr_dim1(rv);
437	                int abs_n = count;
438	                if (abs_n < 0) abs_n = 0 - abs_n;
439	                if (abs_n > rows) { eval_err = 3; return -1; }
440	
441	                int r = arr_new(2, abs_n, cols);
442	                if (r < 0) { eval_err = 5; return -1; }
443	                int start_row = 0;
444	                if (count < 0) start_row = rows - abs_n;
445	                int total = abs_n * cols;
446	                int i = 0;
447	                while (i < total) {
448	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
449	                    i++;
450	                }
451	                return r;
452	            }
453	
454	            eval_err = 4;
455	            return -1;
456	        }
457	
458	        if (res_id == RES_DROP) {
459	            // N drop A: drop first N elements/rows (negative N = from end)
460	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
461	            int count = arr_get(lv, 0);
462	            int rrk = arr_rank(rv);
463	
464	            if (rrk <= 1) {
465	                int sz = arr_size(rv);
466	                int abs_n = count;
467	                if (abs_n < 0) abs_n = 0 - abs_n;
468	                if (abs_n > sz) abs_n = sz;
469	
470	                int new_sz = sz - abs_n;
471	                int r = arr_vector(new_sz);
472	                if (r < 0) { eval_err = 5; return -1; }
473	                int start = abs_n;
474	                if (count < 0) start = 0;
475	                int i = 0;
476	                while (i < new_sz) {
477	                    arr_set(r, i, arr_get(rv, start + i));
478	                    i++;
479	                }
480	                return r;
481	            }
482	
483	            if (rrk == 2) {
484	                int rows = arr_dim0(rv);
485	                int cols = arr_dim1(rv);
486	                int abs_n = count;
487	                if (abs_n < 0) abs_n = 0 - abs_n;
488	                if (abs_n > rows) abs_n = rows;
489	
490	                int new_rows = rows - abs_n;
491	                int r = arr_new(2, new_rows, cols);
492	                if (r < 0) { eval_err = 5; return -1; }
493	                int start_row = abs_n;
494	                if (count < 0) start_row = 0;
495	                int total = new_rows * cols;
496	                int i = 0;
497	                while (i < total) {
498	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
499	                    i++;
500	                }
501	                return r;
502	            }
503	
504	            eval_err = 4;
505	            return -1;
506	        }
507	
508	        if (res_id == RES_CAT) {
509	            // Dyadic cat: catenate two arrays
510	            int lrk = arr_rank(lv);
511	            int rrk = arr_rank(rv);
512	            int lsz = arr_size(lv);
513	            int rsz = arr_size(rv);
514	            int total = lsz + rsz;
515	            int r = arr_vector(total);
516	            if (r < 0) { eval_err = 5; return -1; }
517	            int i = 0;
518	            while (i < lsz) {
519	                arr_set(r, i, arr_get(lv, i));
520	                i++;
521	            }
522	            i = 0;
523	            while (i < rsz) {
524	                arr_set(r, lsz + i, arr_get(rv, i));
525	                i++;
526	            }
527	            return r;
528	        }
529	
530	        // Unknown dyadic function
531	        eval_err = 1;
532	        return -1;
533	    }
534	
535	    if (ty == NODE_BINOP) {
536	        int lv = eval(node_left[n]);
537	        if (eval_err) return -1;
538	        int rv = eval(node_right[n]);
539	        if (eval_err) return -1;
540	
541	        int lrk = arr_rank(lv);
542	        int rrk = arr_rank(rv);
543	        int op = node_val[n];
544	
545	        // Scalar op scalar
546	        if (lrk == 0 && rrk == 0) {
